import './health-food-entry-screen.css';
import { HealthService } from '../../services/health.service.js';
import { navigate, goBack, popOutOfFlow } from '../../router.js';
import { buildSectionPage } from '../../utils/section-page.utils.js';
import './food-log/food-log.component.js';
import type { FoodLog, FoodLogEntry } from './food-log/food-log.component.js';
import type { FoodItem } from '@motivation/shared';
import type { OFFProduct } from '../../services/openfoodfacts.service.js';

const footerTemplate = document.createElement('template');
footerTemplate.innerHTML = `
    <div class="food-entry-footer">
        <a class="manage-meals-link" href="/health/meals">Manage meals →</a>
    </div>
`;
import {
    HEALTH_EVENTS,
    type ScanBarcodeEvent,
    type AiEstimateEvent,
    type SelectLibraryItemEvent,
    type SelectOffItemEvent,
    type SelectMealEvent,
    type LoadMoreOffEvent,
    type FoodLogBackEvent,
    type LogFoodEvent,
    type LogMealEvent,
} from './health-events.js';
import type { ScreenComponent } from '../../types/screen-component.js';
import { createComponentLogger } from '../../utils/component-logger.js';
import { safeExec } from '../../utils/safe-exec.js';

export class HealthFoodEntryScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private foodLog: FoodLog | null = null;
    private queryValue: URLSearchParams | null = null;
    private dateValue: string | null = null;
    private mealValue: string | null = null;
    private readonly log = createComponentLogger('health-food-entry-screen');

    setLoading(): void {}
    setError(err: unknown): void {}
    clearStatus(): void {}

    set date(value: string | null) {
        this.dateValue = value;
    }

    set meal(value: string | null) {
        this.mealValue = value;
    }

    set query(value: URLSearchParams | null) {
        this.queryValue = value;
        if (this.initialized) {
            this.syncViewFromQuery();
        }
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Health', 'health', '/health');
        this.foodLog = document.createElement('food-log') as FoodLog;
        this.foodLog.showScanBarcodeAction = true;
        this.foodLog.showAiEstimateAction = true;

        if (this.mealValue) {
            this.foodLog.defaultMealType = this.mealValue;
        }

        this.foodLog.addEventListener(HEALTH_EVENTS.SELECT_LIBRARY_ITEM, (event: SelectLibraryItemEvent) => {
            const item = event.detail;
            this.navigateWithParam('libraryId', item.id);
        });

        this.foodLog.addEventListener(HEALTH_EVENTS.SELECT_OFF_ITEM, (event: SelectOffItemEvent) => {
            const product = event.detail;
            if (!product.barcode) {
                // OFF entries without a barcode cannot be reconstructed from URL state;
                // show the detail directly without touching history.
                this.foodLog!.showProduct(product);
                return;
            }
            this.navigateWithParam('barcode', product.barcode);
        });

        this.foodLog.addEventListener(HEALTH_EVENTS.SELECT_MEAL, (event: SelectMealEvent) => {
            this.navigateWithParam('mealId', event.detail.id);
        });

        this.foodLog.addEventListener(HEALTH_EVENTS.LOAD_MORE_OFF, (event: LoadMoreOffEvent) => {
            void this.foodLog?.loadMoreOff();
        });

        this.foodLog.addEventListener(HEALTH_EVENTS.FOOD_LOG_BACK, (event: FoodLogBackEvent) => {
            goBack(this.searchUrl());
        });

        this.foodLog.addEventListener(HEALTH_EVENTS.SCAN_BARCODE, (event: ScanBarcodeEvent) => {
            navigate(this.subPath('scanner'));
        });

        this.foodLog.addEventListener(HEALTH_EVENTS.AI_ESTIMATE, (event: AiEstimateEvent) => {
            navigate(this.subPath('ai-estimate'));
        });

        this.foodLog.addEventListener(HEALTH_EVENTS.LOG_FOOD, async (event: LogFoodEvent) => {
            const entry = event.detail;
            return safeExec(this, this.log, async () => {
                await HealthService.createConsumptionEntry({
                    ...entry,
                    date: this.dateValue ?? Temporal.Now.plainDateISO().toString(),
                });
                await this.returnToOrigin();
            });
        });

        this.foodLog.addEventListener(HEALTH_EVENTS.LOG_MEAL, async (event: LogMealEvent) => {
            const { meal_id, meal_type, scale } = event.detail;
            return safeExec(this, this.log, async () => {
                await HealthService.logMeal(meal_id, {
                    date: this.dateValue ?? Temporal.Now.plainDateISO().toString(),
                    meal_type,
                    scale,
                });
                await this.returnToOrigin();
            });
        });

        page.content.appendChild(this.foodLog);
        page.content.appendChild(footerTemplate.content.cloneNode(true));

        this.syncViewFromQuery();
    }

    private navigateWithParam(key: string, value: string): void {
        const url = new URL(window.location.href);
        url.searchParams.set(key, value);
        navigate(url.pathname + url.search);
    }

    private searchUrl(): string {
        return this.dateValue && this.mealValue
            ? `/health/food-entry/${encodeURIComponent(this.dateValue)}/${encodeURIComponent(this.mealValue)}`
            : '/health/food-entry';
    }

    private subPath(segment: 'scanner' | 'ai-estimate'): string {
        return this.dateValue && this.mealValue
            ? `/health/${segment}/${encodeURIComponent(this.dateValue)}/${encodeURIComponent(this.mealValue)}`
            : `/health/${segment}`;
    }

    private syncViewFromQuery(): void {
        if (!this.foodLog) return;

        const barcode = this.queryValue?.get('barcode');
        const libraryId = this.queryValue?.get('libraryId');
        const mealId = this.queryValue?.get('mealId');

        if (barcode) {
            void this.foodLog.lookupBarcode(barcode);
        } else if (libraryId) {
            void this.foodLog.lookupLibraryItem(libraryId);
        } else if (mealId) {
            void this.foodLog.lookupMeal(mealId);
        } else {
            this.foodLog.showSearchView();
        }
    }

    private async returnToOrigin(): Promise<void> {
        const fallback = this.dateValue
            ? `/health/day/${encodeURIComponent(this.dateValue)}`
            : '/health';
        await popOutOfFlow(
            ['/health/food-entry', '/health/scanner', '/health/ai-estimate'],
            fallback,
        );
    }
}

customElements.define('health-food-entry-screen', HealthFoodEntryScreen);
